     1→/**
     2→ * MMS Ingestion Service
     3→ *
     4→ * Processes daily CSV files containing mileage data.
     5→ * Validates records, handles meter events, and updates the database.
     6→ *
     7→ * Data flow:
     8→ * 1. CSV file arrives via file watcher or API upload
     9→ * 2. File is validated (format, size, structure)
    10→ * 3. Records are parsed and validated in batches
    11→ * 4. Anomalies are detected (NEGATIVE, SPIKE, DUPLICATE)
    12→ * 5. Mileage readings are inserted/updated
    13→ * 6. Train current_mileage_km is updated
    14→ * 7. Fleet mileage targets are recalculated
    15→ *
    16→ * Business rules:
    17→ * - Max file size: 10MB
    18→ * - Expected file pattern: mileage_YYYYMMDD.csv
    19→ * - Batch size: 100 records per transaction
    20→ * - Anomaly thresholds: NEGATIVE < 0, SPIKE > 1000 km/day
    21→ * - Meter adjustments are applied to maintain mileage continuity
    22→ *
    23→ * @see specs/004-domain-services.md Section 4.2
    24→ */
    25→
    26→import { eq, and, desc, lte, sql } from 'drizzle-orm';
    27→import * as Papa from 'papaparse';
    28→import * as fs from 'node:fs';
    29→import * as path from 'node:path';
    30→import { BaseService, MmsAttributes } from '../lib/services/base';
    31→import { trains, mileageReadings, meterEvents } from '../lib/db/schema';
    32→import {
    33→  ValidationError,
    34→  FileError,
    35→  BusinessRuleError,
    36→} from '../lib/errors';
    37→import { parseMileageCsvRow } from '../lib/schemas';
    38→import { addJob, QUEUE_NAMES, type IngestionJobData } from '../lib/queue';
    39→import { ingestionMetrics, recordIngestionComplete, recordIngestionAnomaly } from '../lib/metrics';
    40→
    41→// =============================================================================
    42→// Constants
    43→// =============================================================================
    44→
    45→const MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024; // 10MB
    46→const EXPECTED_FILE_PATTERN = /^mileage_\d{8}\.csv$/;
    47→const BATCH_SIZE = 100;
    48→const SPIKE_THRESHOLD_KM = 1000;
    49→const ALERT_THRESHOLD_HOURS = 2;
    50→
    51→// =============================================================================
    52→// Types
    53→// =============================================================================
    54→
    55→/** Anomaly types detected during ingestion */
    56→export type AnomalyType = 'NEGATIVE' | 'SPIKE' | 'DUPLICATE' | 'MISSING' | 'FUTURE_DATE' | 'UNKNOWN_TRAIN';
    57→
    58→/** A detected anomaly in the mileage data */
    59→export interface AnomalyRecord {
    60→  trainNumber: string;
    61→  readingDate: string;
    62→  type: AnomalyType;
    63→  value: number | null;
    64→  message: string;
    65→  rawReading?: number;
    66→  previousReading?: number;
    67→}
    68→
    69→/** Result of meter event detection */
    70→export interface MeterEventRecord {
    71→  trainNumber: string;
    72→  trainId: string;
    73→  eventDate: string;
    74→  eventType: 'RESET' | 'REPLACEMENT' | 'CALIBRATION' | 'SWAP';
    75→  oldReading: number;
    76→  newReading: number;
    77→  adjustmentKm: number;
    78→}
    79→
    80→/** Configuration for the file watcher */
    81→export interface FileWatcherConfig {
    82→  inboxPath: string;
    83→  processedPath: string;
    84→  quarantinePath: string;
    85→  expectedFilePattern?: RegExp;
    86→  maxFileSizeBytes?: number;
    87→  alertThresholdHours?: number;
    88→  pollIntervalMs?: number;
    89→}
    90→
    91→/** Result of file validation */
    92→export interface FileValidationResult {
    93→  valid: boolean;
    94→  errors: string[];
    95→  warnings: string[];
    96→  fileSize: number;
    97→  rowCount?: number;
    98→}
    99→
   100→/** Result of ingestion processing */
   101→export interface IngestionResult {
   102→  jobId: string;
   103→  fileName: string;
   104→  totalRecords: number;
   105→  validRecords: number;
   106→  invalidRecords: number;
   107→  anomalies: AnomalyRecord[];
   108→  meterEvents: MeterEventRecord[];
   109→  processingTimeMs: number;
   110→  trainsUpdated: number;
   111→  status: 'SUCCESS' | 'PARTIAL' | 'FAILED';
   112→  errorMessage?: string;
   113→}
   114→
   115→/** Internal record type after parsing */
   116→interface ParsedMileageRecord {
   117→  trainNumber: string;
   118→  readingDate: string;
   119→  odometerKm: number;
   120→  rowIndex: number;
   121→}
   122→
   123→/** Row validation result */
   124→interface RowValidationResult {
   125→  valid: boolean;
   126→  record?: ParsedMileageRecord;
