/**
 * MMS Simulation Service (Simulation Engine)
 *
 * Enables what-if scenario analysis with persistent storage and comparison capabilities.
 * Uses event-sourcing pattern for tracking changes through deltas.
 *
 * Key responsibilities:
 * - Create scenarios forked from baselines or other scenarios
 * - Apply changes (PM_MOVE, PM_ADD, PM_REMOVE) as deltas
 * - Materialize scenarios by recursively applying deltas
 * - Compare scenarios side-by-side
 * - Promote winning scenarios to new baselines
 *
 * Scenario lifecycle:
 * ACTIVE -> (changes) -> PROMOTED or EXPIRED
 *
 * Auto-expiration: Scenarios expire after 30 days of inactivity.
 *
 * @see specs/004-domain-services.md Section 4.9
 */

import { eq, and, desc, asc, sql, inArray, lte, isNull, count, or } from 'drizzle-orm';
import { addDays, format, parseISO, differenceInDays } from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  scenarios,
  scenarioDeltas,
  scenarioComparisons,
  planBaselines,
  baselinePmSchedule,
  pmSchedule,
  auditLog,
  type Scenario,
  type ScenarioDelta,
  type PlanBaseline,
} from '../lib/db/schema';
import {
  NotFoundError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Status of a scenario in its lifecycle */
export type ScenarioStatus = 'ACTIVE' | 'PROMOTED' | 'DISCARDED' | 'EXPIRED';

/** Delta types for scenario changes */
export type DeltaType =
  | 'PM_MOVE'
  | 'PM_ADD'
  | 'PM_REMOVE'
  | 'CAPACITY_CHANGE'
  | 'TRAIN_STATUS_CHANGE';

/** Entity types that can be modified in scenarios */
export type EntityType = 'pm_schedule' | 'manhour_capacity' | 'train';

/** Fork source specification */
export interface ForkSource {
  type: 'BASELINE' | 'SCENARIO' | 'PRODUCTION';
  id?: string; // Required for BASELINE and SCENARIO, not for PRODUCTION
}

/** Request to create a new scenario */
export interface CreateScenarioRequest {
  name: string;
  description?: string;
  forkFrom: ForkSource;
  userId: string;
  expirationDays?: number; // Default: 30
}

/** Change to apply to a scenario */
export interface ScenarioChange {
  type: DeltaType;
  entityType: EntityType;
  entityId: string;
  oldValues?: Record<string, unknown>;
  newValues?: Record<string, unknown>;
  reason?: string;
}

/** Materialized PM record with scenario context */
export interface MaterializedPmRecord {
  id: string;
  trainId: string;
  pmTypeId: string;
  targetDate: string;
  assignedTrackId?: string | null;
  assignedHours?: number | null;
  status?: string | null;
  constraintStart?: string | null;
  constraintEnd?: string | null;
  isLocked?: boolean;
  // Additional fields for display
  trainNumber?: string;
  pmCode?: string;

